using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // EF Core 9: default discriminator property renamed from "Discriminator" to "$type".
            // Existing 500K documents use "Discriminator" — preserve for data compatibility.
            entity.HasDiscriminator<string>("Discriminator");

            // EF Core 9: id no longer includes discriminator (would be "123" instead of "Product|123").
            // Existing documents have compound ids — preserve the old format.
            entity.HasRootDiscriminatorInJsonId(true);
        });

        // REMOVED: HasIndex() now throws for Cosmos DB entities.
        // Manage indexing via Azure Portal / Bicep / Terraform indexing policy.
    }
}
class Product { public int Id { get; set; } public string Sku { get; set; } }

